// The ototoxic-medication awareness dataset, loaded onto the curated-dataset framework
// (issue #717). Copies the dental-safety.ts / contrast-safety.ts shape: import the
// envelope JSON (generated by scripts/gen-ototoxic.ts), validate it once with
// loadDataset(), and expose the DRUG entries (ototoxic drug-class concepts, matched by
// RxCUI ingredient + synonym) the cross-check consumes. Identity is the concept `key`
// token (fieldStrategy "key"). The registry lists this for the linter; lib/ototoxic.ts
// is the DOMAIN cross-check. Pure — no DB, no network.

import rawOtotoxic from "./data/ototoxic.json";
import { loadDataset } from "./loader";
import { fieldStrategy } from "./matcher";
import type { OtotoxicDrugEntry, OtotoxicMeta } from "@/scripts/gen-ototoxic";

export type {
  OtotoxicDrugEntry,
  OtotoxicMeta,
  OtotoxicCategory,
} from "@/scripts/gen-ototoxic";

// The validated dataset (envelope + guarantees). Throws at module load if the committed
// JSON ever violates the contract — a loud, early failure.
export const ototoxicDataset = loadDataset<OtotoxicDrugEntry, OtotoxicMeta>(
  rawOtotoxic
);

// Identity strategy: the concept `key` token, case-folded. For the linter.
export const ototoxicKeyStrategy = fieldStrategy("key");

// The ototoxic drug-class entries (concepts) the cross-check consumes.
export const OTOTOXIC_DRUG_ENTRIES: OtotoxicDrugEntry[] =
  ototoxicDataset.entries;
